// Selecciona leads que esperan chat y AUN no tienen telefono.
const items = $input.all();
const out = [];
const now = Date.now();
const MAX_MS = 48 * 60 * 60 * 1000; // 48h: tras esto se marca sin_whatsapp

for (const it of items) {
  const r = it.json || {};
  const tel = (r.telefono || '').toString().trim();
  const estado = (r.estado || '').toString().trim();
  const pendiente = !tel && (estado === 'esperando_chat' || estado === 'chat_iniciado');
  if (!pendiente) continue;
  if (!r.kommo_lead_id) continue;
  const ts = Date.parse(r.timestamp);
  const ageMs = isNaN(ts) ? 0 : (now - ts);
  out.push({ json: {
    kommo_lead_id: String(r.kommo_lead_id),
    ref_code: r.ref_code || '',
    expirado: ageMs > MAX_MS
  }});
}
return out;

