    0x19a4c116, 0x1e376c08, 0x2748774c, 0x34b0bcb5, 0x391c0cb3, 0x4ed8aa4a, 0x5b9cca4f, 0x682e6ff3,
    0x748f82ee, 0x78a5636f, 0x84c87814, 0x8cc70208, 0x90befffa, 0xa4506ceb, 0xbef9a3f7, 0xc67178f2
  ];
  var words = [];
  var asciiLength = ascii.length * 8;
  ascii += '\x80'; 
  while (ascii[lengthProperty] % 64 - 56) ascii += '\x00'; 
  for (i = 0; i < ascii[lengthProperty]; i++) {
    j = ascii.charCodeAt(i);
    words[i >> 2] |= j << (24 - (i % 4) * 8);
  }
  words[words[lengthProperty]] = ((asciiLength / maxWord) | 0);
  words[words[lengthProperty]] = (asciiLength | 0);
  for (j = 0; j < words[lengthProperty];) {
    var w = words.slice(j, j += 16); 
    var oldHash = hash.slice(0);
    for (i = 0; i < 64; i++) {
      var w15 = w[i - 15], w2 = w[i - 2];
      var s0 = rightRotate(w15, 7) ^ rightRotate(w15, 18) ^ (w15 >>> 3);
      var s1 = rightRotate(w2, 17) ^ rightRotate(w2, 19) ^ (w2 >>> 10);
      var ch = (hash[4] & hash[5]) ^ (~hash[4] & hash[6]);
      var maj = (hash[0] & hash[1]) ^ (hash[0] & hash[2]) ^ (hash[1] & hash[2]);
      var temp1 = hash[7] + (rightRotate(hash[4], 6) ^ rightRotate(hash[4], 11) ^ rightRotate(hash[4], 25)) + ch + k[i] + (w[i] = (i < 16 ? w[i] : (w[i - 16] + s0 + w[i - 7] + s1) | 0));
      var temp2 = (rightRotate(hash[0], 2) ^ rightRotate(hash[0], 13) ^ rightRotate(hash[0], 22)) + maj;
      hash = [(temp1 + temp2) | 0].concat(hash); 
      hash[4] = (hash[4] + temp1) | 0;
      hash.pop();
    }
    for (i = 0; i < 8; i++) {
      hash[i] = (hash[i] + oldHash[i]) | 0;
    }
  }
  const hex = [];
  for (i = 0; i < 8; i++) {
    var h = hash[i];
    if (h < 0) h += maxWord;
    var hexStr = h.toString(16);
    while (hexStr.length < 8) hexStr = '0' + hexStr;
    hex.push(hexStr);
  }
  return Buffer.from(hex.join(''), 'hex');
}

function modPow(base, exponent, modulus) {
  if (modulus === 1n) return 0n;
  let result = 1n;
  base = base % modulus;
  while (exponent > 0n) {
    if (exponent % 2n === 1n) {
      result = (result * base) % modulus;
    }
    exponent = exponent >> 1n;
    base = (base * base) % modulus;
  }
  return result;
}

function base64UrlToBigInt(b64url) {
  let b64 = b64url.replace(/-/g, '+').replace(/_/g, '/');
  while (b64.length % 4) b64 += '=';
  const buf = Buffer.from(b64, 'base64');
  return BigInt('0x' + buf.toString('hex'));
}

function bigIntToBuffer(num, width) {
  let hex = num.toString(16);
  if (hex.length % 2) hex = '0' + hex;
  let buf = Buffer.from(hex, 'hex');
  if (buf.length < width) {
    const pad = Buffer.alloc(width - buf.length, 0);
    buf = Buffer.concat([pad, buf]);
  }
  return buf;
}

function base64UrlEncode(buf) {
  return buf.toString('base64')
    .replace(/=/g, '')
    .replace(/\+/g, '-')
    .replace(/\//g, '_');
}

function signRS256(message, n_b64, d_b64) {
  const n = base64UrlToBigInt(n_b64);
  const d = base64UrlToBigInt(d_b64);
  const hash = sha256(message);
  const digestInfoPrefix = Buffer.from([
    0x30, 0x31, 0x30, 0x0d, 0x06, 0x09, 0x60, 0x86, 0x48, 0x01, 0x65, 0x03, 0x04, 0x02, 0x01, 0x05, 0x00, 0x04, 0x20
  ]);
  const digestInfo = Buffer.concat([digestInfoPrefix, hash]);
  const k = 256; 
  const psSize = k - 3 - digestInfo.length;
  const ps = Buffer.alloc(psSize, 0xFF);
  const paddedBlock = Buffer.concat([
    Buffer.from([0x00, 0x01]),
    ps,
    Buffer.from([0x00]),
    digestInfo
  ]);
  const m = BigInt('0x' + paddedBlock.toString('hex'));
  const s = modPow(m, d, n);
  const sigBuf = bigIntToBuffer(s, k);
  return base64UrlEncode(sigBuf);
}

const header = { alg: "RS256", typ: "JWT" };
const now = Math.floor(Date.now() / 1000);
const payload = {
  iss: client_email,
  scope: "https://www.googleapis.com/auth/spreadsheets",
  aud: "https://oauth2.googleapis.com/token",
  exp: now + 3600,
  iat: now
};

const encodedHeader = base64UrlEncode(Buffer.from(JSON.stringify(header)));
const encodedPayload = base64UrlEncode(Buffer.from(JSON.stringify(payload)));
const signatureInput = encodedHeader + "." + encodedPayload;
const signature = signRS256(signatureInput, n_b64, d_b64);
const jwt = signatureInput + "." + signature;

return [{
  json: {
    jwt: jwt,
    timestamp: new Date().toISOString()
  }
}];

const prevNode = $('Resolver telefono o expirar').item.json;
const kommoLeadId = prevNode.kommo_lead_id;
const telefono = prevNode.telefono;
const contactId = prevNode.kommo_contact_id;
const estado = prevNode.estado;

const sheetData = $json.values || [];
let rowIndex = -1;
let matchedRow = null;

for (let i = 0; i < sheetData.length; i++) {
  const row = sheetData[i];
  if (row[6] === kommoLeadId) {
    rowIndex = i + 1; // 1-indexed row number
    matchedRow = [...row];
    break;
  }
}

if (rowIndex === -1) {
  throw new Error("No se encontro el kommo_lead_id " + kommoLeadId + " en la hoja.");
}

// Update the cells in the matched row
matchedRow[7] = estado; // estado
matchedRow[8] = telefono; // telefono
matchedRow[9] = contactId; // kommo_contact

return [{
  json: {
    found: true,
    rowNumber: rowIndex,
    range: "Leads!A" + rowIndex + ":L" + rowIndex,
    values: [matchedRow]
  }
}];
